export class DataService {
  private data: DataRecord[] = [];

  async getAll(): Promise<DataRecord[]> {
    return [...this.data];
  }

  async getById(id: string): Promise<DataRecord | null> {
    const record = this.data.find(r => r.id === id) || null;
    return record;
  }

  async create(record: Omit<DataRecord, 'id'>): Promise<DataRecord> {
    const newRecord = { ...record, id: String(Date.now()) };
    this.data.push(newRecord);
    return newRecord;
  }

  async delete(id: string): Promise<boolean> {
    const index = this.data.findIndex(r => r.id === id);
    if (index === -1) {
      return false;
    }
    this.data.splice(index, 1);
    return true;
  }
}
